console.log("🚀 HYBRID WA NOTIFIER v3");

let unlocked = false;
window.addEventListener("click", () => {
    unlocked = true;
    console.log("🔓 Audio unlocked");
}, { once: true });

let lastPlayed = 0;
const COOLDOWN = 1500;

function playSound(source) {
    if (!unlocked) return;

    const now = Date.now();
    if (now - lastPlayed < COOLDOWN) return;
    lastPlayed = now;

    chrome.storage.local.get(["selectedSounds"], (res) => {
        let selected = res.selectedSounds || ["fearstophantomlouder"];

        if (selected.length === 0) return;

        const key = selected[Math.floor(Math.random() * selected.length)];
        const src = SOUND_MAP[key];

        const audio = new Audio(src);
        audio.play()
            .then(() => console.log("🔊 Played:", key))
            .catch(err => console.log("❌", err));
    });
}

// ─── APPROACH: Poll the unread badge count across ALL chats ───────────────────
// Each chat in the sidebar has an unread count badge.
// Summing them gives total unread messages — not just unread chats.
// If that number goes UP, a new message arrived.

let lastUnreadCount = 0;
let isFirstPoll = true;

function getTotalUnreadMessages() {
    // These spans hold the unread message count per chat (e.g. "3", "12")
    const badges = document.querySelectorAll('[aria-label="Unread message"]');
    // Also grab numeric badges like (3) next to chat names
    const countSpans = document.querySelectorAll('span[data-testid="icon-unread-count"]');

    let total = 0;

    countSpans.forEach(span => {
        const val = parseInt(span.textContent.trim(), 10);
        if (!isNaN(val)) total += val;
    });

    // Fallback: count badge dots if numeric spans are absent
    if (total === 0) {
        total = badges.length;
    }

    return total;
}

function getTotalUnreadMessages() {
    let total = 0;
    const seen = new Set();
    
    document.querySelectorAll('[role="gridcell"]').forEach(cell => {
        if (seen.has(cell)) return;
        seen.add(cell);
        
        const spans = cell.querySelectorAll('span');
        for (const s of spans) {
            const text = s.textContent.trim();
            const val = parseInt(text, 10);
            // Must be a pure number, no other text
            if (!isNaN(val) && val > 0 && String(val) === text) {
                total += val;
                break; // only first match per gridcell
            }
        }
    });
    
    console.log("🔢 Total unread:", total); // remove after confirming
    return total;
}

setInterval(() => {
    const current = getTotalUnreadMessages();

    if (isFirstPoll) {
        lastUnreadCount = current;
        isFirstPoll = false;
        console.log("📊 Initial unread count:", current);
        return;
    }

    if (current > lastUnreadCount) {
        console.log(`📩 Unread went ${lastUnreadCount} → ${current}`);
        playSound("badge-count");
    }

    lastUnreadCount = current;
}, 800);